-- Complete setup script for DB_Countries table with all 137 countries
-- Run this in SQL Server Management Studio

-- Step 1: Drop table if exists and recreate with all columns
IF OBJECT_ID('DB_Countries', 'U') IS NOT NULL
    DROP TABLE [DB_Countries];

CREATE TABLE [DB_Countries] (
    [Id] int NOT NULL IDENTITY(1,1),
    [Country] nvarchar(100) NOT NULL,
    [SNG_total_revenue_pct_gdp] decimal(18,4) NULL,
    [SNG_grants_subsidies_pct_gdp] decimal(18,4) NULL,
    [OSR_pct_gdp] decimal(18,4) NULL,
    [GDP_nominal_usd] decimal(22,2) NULL,
    [Population_total] bigint NULL,
    [OSR_pc_proxy_usd] decimal(18,2) NULL,
    [Government_Type] nvarchar(50) NULL,
    [OSR_Data_Complete] nvarchar(10) NULL,
    [Income_Level] nvarchar(50) NULL,
    [Income_Group] nvarchar(50) NULL,
    [SNG_total_rev_pc_usd] decimal(18,4) NULL,
    [Revenue_Autonomy] decimal(18,9) NULL,
    [OSR_pc_derived_usd] decimal(18,4) NULL,
    [CurrencyCode] nvarchar(10) NULL,
    [CurrencySymbol] nvarchar(10) NULL,
    CONSTRAINT [PK_DB_Countries] PRIMARY KEY ([Id])
);

PRINT 'Table DB_Countries created successfully with all columns including CurrencyCode and CurrencySymbol';

-- Step 2: Insert all 137 countries

PRINT 'Inserted 137 countries into DB_Countries';

-- Step 3: Update migration history
IF NOT EXISTS (SELECT 1 FROM [__EFMigrationsHistory] WHERE [MigrationId] LIKE '%Countries%')
BEGIN
    VALUES ('20251207200000_CreateDBCountriesTable', '9.0.4');
    PRINT 'Migration history recorded';
END

-- Step 4: Verify
SELECT COUNT(*) AS TotalCountries FROM [DB_Countries];
SELECT TOP 5 Country, CurrencyCode, CurrencySymbol, Income_Level FROM [DB_Countries];
PRINT 'Setup complete!';
